];
const runTest = async (ep) => {
  const start = Date.now();
  const t = ep.timeout || 15000;
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: BASE + '/' + ep.path,
      headers: HEADERS,
      body: ep.body,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      timeout: t
    });
    const ms = Date.now() - start;
    const status = r.statusCode || 0;
    const pass = status >= 200 && status < 400;
    return {name: ep.name, status: pass ? 'PASS' : 'FAIL', http: status, ms: ms, detail: 'HTTP ' + status + ' in ' + ms + 'ms'};
  } catch (e) {
    return {name: ep.name, status: 'ERROR', http: 0, ms: Date.now() - start, detail: (e.message || '').substring(0, 80)};
  }
};
const results = await Promise.all(endpoints.map(runTest));
const passed = results.filter(r => r.status === 'PASS').length;
const failed = results.filter(r => r.status === 'FAIL').length;
const errors = results.filter(r => r.status === 'ERROR').length;
const total = results.length;
return [{json: {summary: {total: total, passed: passed, failed: failed, errors: errors, pass_rate: ((passed / total) * 100).toFixed(0) + '%'}, results: results, timestamp: new Date().toISOString()}}];

